@startuml
!theme base

class "Task" as Task {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Task
}

class "UserStory" as UserStory {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  UserStory
}

class "Sprint" as Sprint {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Sprint
}

class "Typology" as Typology {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Typology
}

class "Project" as Project {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Project
}

class "Resource" as Resource {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Resource
}

class "ProfileRequest" as ProfileRequest {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  ProfileRequest
}

class "Profile" as Profile {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  Profile
}

class "User" as User {
  <<AGGREGATE ROOT>>
  <<ENTITY>>
  User
}

Task --|> Sprint
Sprint --|> UserStory
UserStory --|> Sprint
Sprint --|> Project
Project --|> Resource
Resource --|> User
User --|> Profile
Profile --|> User
ProfileRequest --|> User
ProfileRequest --|> Typology
Typology --|> User

@enduml
